mapper.select:
select count(materials_id)
from course_materials cm
inner join course co on cm.course_id = co.course_id
inner join student_course sc on co.course_id = sc.course_id

    sc.loginID = #{loginID}

        AND co.course_id = #{course_id}

select cm.materials_id as materials_id , cm.title , co.title AS course_title , cm.content , register_date , update_date , cm.course_id , cm.file_id , fl.name as file_name from course_materials cm inner join course co on cm.course_id = co.course_id inner join student_course sc on co.course_id = sc.course_id inner join file fl on cm.file_id = fl.file_id
sc.loginID = #{loginID}
AND co.course_id = #{course_id}
order by cm.materials_id DESC LIMIT #{start}, #{limit}
